define('tiny_imageia/options', ['editor_tiny/options', 'tiny_imageia/common'], function(TinyOptions, Common) {
  const pluginName = Common.pluginName;
  const configuredOptionName = TinyOptions.getPluginOptionName(pluginName, 'configured');
  const contextIdOptionName = TinyOptions.getPluginOptionName(pluginName, 'contextid');
  const register = (editor) => {
    editor.options.register(configuredOptionName, {processor: 'string'});
    editor.options.register(contextIdOptionName, {processor: 'string'});
  };
  const isConfigured = (editor) => editor.options.get(configuredOptionName) === '1';
  const getContextId = (editor) => editor.options.get(contextIdOptionName) || '0';
  return {register, isConfigured, getContextId};
});
